class Solution {
    public int racecar(int target) {
        int n = target;
        int dp[] = new int[n + 2];
        Arrays.fill(dp, n + 1);
        dp[0] = 0;
        dp[1] = 1;
        for (int i = 2; i <= n; i++) {
            k = (int) Math.floor(Math.log(i) / Math.log(2));
            if ((1 << k) == i) {
                dp[i] = k;
            } else {
                for (int j = 0; j < k; j++) {
                    dp[i] = Math.min(dp[i], dp[(1 << k) - (1 << j)] + j + k + 1);
                }
            }
        }
        return dp[n];
    }
}
